class Solution(object):
    def splitArray(self, nums):
        n = len(nums)
        # inc[i]: is nums[0..i] strictly increasing?
        inc = [True] * n
        for i in range(1, n):
            inc[i] = inc[i - 1] and nums[i] > nums[i - 1]

        # dec[i]: is nums[i..n-1] strictly decreasing?
        dec = [True] * n
        for i in range(n - 2, -1, -1):
            dec[i] = dec[i + 1] and nums[i] > nums[i + 1]

        prefix = [0] * (n + 1)
        for i in range(n):
            prefix[i + 1] = prefix[i] + nums[i]

        ans = float('inf')
        for i in range(n - 1):
            if inc[i] and dec[i + 1]:
                left_sum = prefix[i + 1]
                right_sum = prefix[n] - prefix[i + 1]
                ans = min(ans, abs(left_sum - right_sum))

        return ans if ans != float('inf') else -1
